@namespace Lumeo
@implements IAsyncDisposable
@inject IComponentInteropService Interop

@{
    var context = new ToggleGroupContext(Type, _selectedItems, Variant, Size, EventCallback.Factory.Create<string>(this, ToggleItem), GetTabIndex, _itemValues, _itemIds, _itemDisabled);
}

<div id="@_id" role="group" class="@CssClass" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public ToggleGroupType Type { get; set; } = ToggleGroupType.Single;
    [Parameter] public ToggleGroupVariant Variant { get; set; } = ToggleGroupVariant.Default;
    [Parameter] public Lumeo.Size Size { get; set; } = Lumeo.Size.Md;
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    [Parameter] public IEnumerable<string>? SelectedValues { get; set; }
    [Parameter] public EventCallback<IEnumerable<string>> SelectedValuesChanged { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly HashSet<string> _selectedItems = new();
    private readonly string _id = LumeoIds.New("togglegroup");

    // Ordered item registry — populated by ToggleGroupItem children. Drives the
    // roving tabindex (one tab stop) and arrow-key focus movement.
    private readonly List<string> _itemValues = new();
    private readonly Dictionary<string, string> _itemIds = new();
    private readonly Dictionary<string, bool> _itemDisabled = new();

    // Last-seen bound parameters — lets us distinguish "consumer cleared the
    // binding to null" (sync: clear the selection) from "consumer never binds
    // at all" (uncontrolled usage: leave the internally-toggled selection alone).
    private string? _lastValue;
    private IEnumerable<string>? _lastSelectedValues;

    private string CssClass => Cx.Merge("flex items-center gap-1", Class);

    // Roving tabindex: the first selected item is the tab stop; if nothing is
    // selected, the first ENABLED item holds it. Arrow keys then move focus among
    // the rest (Radix ToggleGroup: arrows move focus, Enter/Space toggles).
    private string GetTabIndex(string value, bool disabled)
    {
        if (disabled) return "-1";
        var firstSelected = _itemValues.FirstOrDefault(v => _selectedItems.Contains(v) && !IsItemDisabled(v));
        if (firstSelected is not null) return value == firstSelected ? "0" : "-1";
        return _itemValues.FirstOrDefault(v => !IsItemDisabled(v)) == value ? "0" : "-1";
    }

    private bool IsItemDisabled(string value) =>
        _itemDisabled.TryGetValue(value, out var d) && d;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (_itemValues.Count == 0) return;

        // The reference point for navigation is the focused item. We can't read
        // document.activeElement from C#, so we navigate relative to the current
        // tab stop (first selected, else first enabled) — matching where focus
        // sits when the user tabs in, and arrow presses chain from there.
        var anchor = _itemValues.FirstOrDefault(v => _selectedItems.Contains(v) && !IsItemDisabled(v))
            ?? _itemValues.FirstOrDefault(v => !IsItemDisabled(v));
        if (anchor is null) return;
        var idx = _focusValue is not null && _itemValues.Contains(_focusValue)
            ? _itemValues.IndexOf(_focusValue)
            : _itemValues.IndexOf(anchor);

        string? target = e.Key switch
        {
            "ArrowRight" or "ArrowDown" => FindNextEnabled(idx, 1),
            "ArrowLeft" or "ArrowUp" => FindNextEnabled(idx, -1),
            "Home" => _itemValues.FirstOrDefault(v => !IsItemDisabled(v)),
            "End" => _itemValues.LastOrDefault(v => !IsItemDisabled(v)),
            _ => null
        };
        if (target is null) return;

        _focusValue = target;
        if (_itemIds.TryGetValue(target, out var id))
        {
            try { await Interop.FocusElement(id); }
            catch (JSDisconnectedException) { }
        }
    }

    // Tracks the last item we moved focus to via arrow keys, so successive
    // presses chain (right, right, right) rather than always restarting from the
    // selected item.
    private string? _focusValue;

    private string? FindNextEnabled(int currentIdx, int direction)
    {
        if (_itemValues.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < _itemValues.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = _itemValues.Count - 1;
            else if (idx >= _itemValues.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!IsItemDisabled(_itemValues[idx])) return _itemValues[idx];
        }
        return null;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                _id,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft", "Home", "End" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    private bool _pdRegistered;

    public async ValueTask DisposeAsync()
    {
        if (!_pdRegistered) return;
        try { await Interop.UnregisterPreventDefaultKeys(_id); }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }

    protected override void OnParametersSet()
    {
        if (Type == ToggleGroupType.Single)
        {
            if (Value is not null)
            {
                _selectedItems.Clear();
                _selectedItems.Add(Value);
            }
            else if (_lastValue is not null)
            {
                // Bound value was reset to null — drop the stale selection.
                _selectedItems.Clear();
            }
            _lastValue = Value;
        }
        else if (Type == ToggleGroupType.Multiple)
        {
            if (SelectedValues is not null)
            {
                _selectedItems.Clear();
                foreach (var v in SelectedValues) _selectedItems.Add(v);
            }
            else if (_lastSelectedValues is not null)
            {
                // Bound collection was reset to null — drop the stale selection.
                _selectedItems.Clear();
            }
            _lastSelectedValues = SelectedValues;
        }
    }

    private async Task ToggleItem(string value)
    {
        if (_selectedItems.Contains(value))
        {
            _selectedItems.Remove(value);
        }
        else
        {
            if (Type == ToggleGroupType.Single)
            {
                _selectedItems.Clear();
            }
            _selectedItems.Add(value);
        }
        StateHasChanged();

        if (Type == ToggleGroupType.Single)
            await ValueChanged.InvokeAsync(_selectedItems.FirstOrDefault());
        else
            await SelectedValuesChanged.InvokeAsync(_selectedItems.ToList());
    }

    public enum ToggleGroupType { Single, Multiple }
    public enum ToggleGroupVariant { Default, Outline }

    public record ToggleGroupContext(
        ToggleGroupType Type,
        HashSet<string> SelectedItems,
        ToggleGroupVariant Variant,
        Lumeo.Size Size,
        EventCallback<string> Toggle,
        Func<string, bool, string> GetTabIndex,
        List<string> ItemValues,
        Dictionary<string, string> ItemIds,
        Dictionary<string, bool> ItemDisabled)
    {
        public bool IsSelected(string value) => SelectedItems.Contains(value);
    }
}

@namespace Lumeo
@implements IDisposable
@inject Lumeo.Services.IComponentInteropService Interop

<button @ref="_el" id="@_itemId" type="button" aria-pressed="@IsPressed.ToString().ToLower()" tabindex="@Context.GetTabIndex(Value, Disabled)" class="@CssClass" @onclick="Toggle" disabled="@Disabled" @attributes="AdditionalAttributes">
    @ChildContent
</button>

@code {
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }

    /// <summary>
    /// Visual feedback when the item is pressed. Default is
    /// <see cref="Button.ButtonPressEffect.None"/>.
    /// </summary>
    [Parameter] public Button.ButtonPressEffect PressEffect { get; set; } = Button.ButtonPressEffect.None;

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    [CascadingParameter] public ToggleGroup.ToggleGroupContext Context { get; set; } = default!;

    private Microsoft.AspNetCore.Components.ElementReference _el;
    private readonly string _itemId = LumeoIds.New("toggle-item");
    private string? _registeredValue;

    private bool IsPressed => Context.SelectedItems.Contains(Value);

    protected override void OnParametersSet()
    {
        if (Context is null) return;

        // Register into the parent's shared registry (ownership-guarded re-key so
        // we never delete a sibling's live entry) so roving tabindex + arrow-key
        // focus movement see this item in DOM order with its current Disabled state.
        if (_registeredValue is not null && _registeredValue != Value
            && Context.ItemIds.TryGetValue(_registeredValue, out var oldId) && oldId == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
        if (!Context.ItemValues.Contains(Value))
            Context.ItemValues.Add(Value);
        Context.ItemIds[Value] = _itemId;
        Context.ItemDisabled[Value] = Disabled;
        _registeredValue = Value;
    }

    private string CssClass => Cx.Merge(VariantClasses, SizeClasses, BaseClasses, "cursor-pointer disabled:cursor-not-allowed", PressEffectClass, Class);

    // gap-1.5 mirrors Button's base gap so icon+label children space cleanly without
    // requiring consumers to add Class="gap-1.5" manually. Single-child renders are
    // unaffected (gap only matters when there are multiple flex children).
    private const string BaseClasses = "inline-flex items-center justify-center gap-1.5 rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private string? PressEffectClass => PressEffect switch
    {
        Button.ButtonPressEffect.Scale => "lumeo-press-scale",
        Button.ButtonPressEffect.Brightness => "lumeo-press-brightness",
        Button.ButtonPressEffect.Ripple => "lumeo-press-ripple",
        _ => null
    };

    private string VariantClasses => (Context.Variant, IsPressed) switch
    {
        (ToggleGroup.ToggleGroupVariant.Default, true) => "bg-accent text-accent-foreground",
        (ToggleGroup.ToggleGroupVariant.Default, false) => "bg-transparent hover:bg-muted hover:text-muted-foreground",
        (ToggleGroup.ToggleGroupVariant.Outline, true) => "bg-accent text-accent-foreground border border-input",
        (ToggleGroup.ToggleGroupVariant.Outline, false) => "border border-input bg-transparent hover:bg-accent hover:text-accent-foreground",
        _ => ""
    };

    private string SizeClasses => Context.Size switch
    {
        Lumeo.Size.Sm => "h-8 px-2",
        Lumeo.Size.Lg => "h-10 px-4",
        _ => "h-9 px-3"
    };

    private async Task Toggle()
    {
        if (!Disabled)
        {
            await Context.Toggle.InvokeAsync(Value);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && PressEffect == Button.ButtonPressEffect.Ripple)
        {
            try
            {
                await Interop.RippleAttachAsync(_el);
            }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        }
    }

    public void Dispose()
    {
        // Conditionally-removed items must leave the registry (ownership-guarded).
        if (Context is not null && _registeredValue is not null
            && Context.ItemIds.TryGetValue(_registeredValue, out var id) && id == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
    }
}
